mapper.select:
SELECT account_id, tenant_id, total_balance, frozen_balance, version
FROM t_maintenance_fund_account
WHERE tenant_id = #{tenantId}
  AND account_level = #{accountLevel}
  AND reference_id = #{referenceId}
FOR UPDATE

mapper.update:
UPDATE t_maintenance_fund_account
SET total_balance = total_balance - #{amount},
    version = version + 1,
    update_time = CURRENT_TIMESTAMP
WHERE account_id = #{accountId}
  AND version = #{expectedVersion}
  AND total_balance - frozen_balance >= #{amount}

UPDATE t_maintenance_fund_account
SET total_balance = total_balance + #{amount},
    version = version + 1,
    update_time = CURRENT_TIMESTAMP
WHERE account_id = #{accountId}
  AND version = #{expectedVersion}

